    CUST_REQ_SEQ
    , REQ_TYPE
    , USERID
    , CSTMR_NAME
    , MOBILE_NO
    , CSTMR_NATIVE_RRN
    , CONTRACT_NUM
    , CSTMR_TYPE
    , ONLINE_AUTH_TYPE
    , ONLINE_AUTH_INFO
    , CRET_ID
    , SYS_RDATE
    , ETC_MOBILE
) VALUES (
    #{custReqSeq}
    , 'NC'
    , #{userid}
    , #{grCstmrName}
    , #{mobileNo}
    , #{grCstmrNativeRrn}
    , #{contractNum}
    , #{grCstmrType}
    , #{grOnlineAuthType}
    , #{grOnlineAuthInfo}
    , #{userid}
    , SYSDATE
    , #{etcMobile}
)

