UPDATE NMCP_CUST_REQUEST_MST
SET ONLINE_AUTH_TYPE = #{grOnlineAuthType}
  , ONLINE_AUTH_INFO = #{grOnlineAuthInfo}
WHERE CUST_REQ_SEQ = #{custReqSeq}

UPDATE NMCP_CUST_REQUEST_NAME_CHG
SET ONLINE_AUTH_TYPE = #{onlineAuthType}
